import { useState, useEffect } from 'react';
import type { User, Product, Cart, Category } from './types';

// API Base URL
const API_BASE_URL = import.meta.env.VITE_API_URL || 'http://localhost:3000/api';

// ============================================================
// 通用工具函数
// ============================================================

/** 获取认证 Token */
const getAuthToken = (): string | null => {
  return localStorage.getItem('token');
};

/** API 请求封装 */
const apiRequest = async <T>(
  endpoint: string,
  options: RequestInit = {}
): Promise<T> => {
  const token = getAuthToken();
  const headers: HeadersInit = {
    'Content-Type': 'application/json',
    ...(token && { Authorization: `Bearer ${token}` }),
    ...options.headers,
  };

  const response = await fetch(`${API_BASE_URL}${endpoint}`, {
    ...options,
    headers,
  });

  if (!response.ok) {
    const errorData = await response.json().catch(() => ({}));
    throw new Error(errorData.error?.message || `HTTP error! status: ${response.status}`);
  }

  return response.json();
};

// ============================================================
// 认证相关组件
// ============================================================

interface AuthFormProps {
  onSuccess: (user: User, token: string) => void;
}

function LoginForm({ onSuccess }: AuthFormProps) {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      const response = await apiRequest<{ user: User; token: string }>('/auth/login', {
        method: 'POST',
        body: JSON.stringify({ email, password }),
      });

      localStorage.setItem('token', response.token);
      onSuccess(response.user, response.token);
    } catch (err) {
      setError(err instanceof Error ? err.message : '登录失败');
    } finally {
      setLoading(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="auth-form">
      <h2>登录</h2>
      {error && <div className="error-message">{error}</div>}
      <div className="form-group">
        <label htmlFor="login-email">邮箱</label>
        <input
          id="login-email"
          type="email"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          required
        />
      </div>
      <div className="form-group">
        <label htmlFor="login-password">密码</label>
        <input
          id="login-password"
          type="password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
          required
        />
      </div>
      <button type="submit" disabled={loading}>
        {loading ? '登录中...' : '登录'}
      </button>
    </form>
  );
}

function RegisterForm({ onSuccess }: AuthFormProps) {
  const [username, setUsername] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      const response = await apiRequest<{ user: User; token: string }>('/auth/register', {
        method: 'POST',
        body: JSON.stringify({ username, email, password }),
      });

      localStorage.setItem('token', response.token);
      onSuccess(response.user, response.token);
    } catch (err) {
      setError(err instanceof Error ? err.message : '注册失败');
    } finally {
      setLoading(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="auth-form">
      <h2>注册</h2>
      {error && <div className="error-message">{error}</div>}
      <div className="form-group">
        <label htmlFor="register-username">用户名</label>
        <input
          id="register-username"
          type="text"
          value={username}
          onChange={(e) => setUsername(e.target.value)}
          required
          minLength={2}
          maxLength={50}
        />
      </div>
      <div className="form-group">
        <label htmlFor="register-email">邮箱</label>
        <input
          id="register-email"
          type="email"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          required
        />
      </div>
      <div className="form-group">
        <label htmlFor="register-password">密码</label>
        <input
          id="register-password"
          type="password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
          required
          minLength={6}
          maxLength={128}
        />
      </div>
      <button type="submit" disabled={loading}>
        {loading ? '注册中...' : '注册'}
      </button>
    </form>
  );
}

interface AuthViewProps {
  user: User | null;
  onLogout: () => void;
  onAuthSuccess: (user: User, token: string) => void;
}

function AuthView({ user, onLogout, onAuthSuccess }: AuthViewProps) {
  const [isLogin, setIsLogin] = useState(true);

  if (user) {
    return (
      <div className="auth-status">
        <span>欢迎, {user.username}</span>
        <button onClick={onLogout}>退出登录</button>
      </div>
    );
  }

  return (
    <div className="auth-container">
      <div className="auth-tabs">
        <button
          className={isLogin ? 'active' : ''}
          onClick={() => setIsLogin(true)}
        >
          登录
        </button>
        <button
          className={!isLogin ? 'active' : ''}
          onClick={() => setIsLogin(false)}
        >
          注册
        </button>
      </div>
      {isLogin ? (
        <LoginForm onSuccess={onAuthSuccess} />
      ) : (
        <RegisterForm onSuccess={onAuthSuccess} />
      )}
    </div>
  );
}

// ============================================================
// 商品浏览组件
// ============================================================

interface ProductCardProps {
  product: Product;
  onAddToCart: (productId: number, quantity: number) => void;
  isAuthenticated: boolean;
}

function ProductCard({ product, onAddToCart, isAuthenticated }: ProductCardProps) {
  const [quantity, setQuantity] = useState(1);

  const handleAddToCart = () => {
    if (isAuthenticated) {
      onAddToCart(product.id, quantity);
    } else {
      alert('请先登录后再添加商品到购物车');
    }
  };

  return (
    <div className="product-card">
      <img src={product.imageUrl} alt={product.name} className="product-image" />
      <h3 className="product-name">{product.name}</h3>
      <p className="product-description">{product.description}</p>
      <div className="product-price">¥{product.price.toFixed(2)}</div>
      <div className="product-stock">库存: {product.stock}</div>
      <div className="product-actions">
        <input
          type="number"
          min="1"
          max={product.stock}
          value={quantity}
          onChange={(e) => setQuantity(Math.max(1, parseInt(e.target.value) || 1))}
          className="quantity-input"
        />
        <button onClick={handleAddToCart} disabled={product.stock === 0}>
          {product.stock === 0 ? '缺货' : '加入购物车'}
        </button>
      </div>
    </div>
  );
}

interface ProductListProps {
  products: Product[];
  onAddToCart: (productId: number, quantity: number) => void;
  isAuthenticated: boolean;
}

function ProductList({ products, onAddToCart, isAuthenticated }: ProductListProps) {
  if (products.length === 0) {
    return <div className="empty-state">暂无商品</div>;
  }

  return (
    <div className="product-grid">
      {products.map((product) => (
        <ProductCard
          key={product.id}
          product={product}
          onAddToCart={onAddToCart}
          isAuthenticated={isAuthenticated}
        />
      ))}
    </div>
  );
}

// ============================================================
// 购物车组件
// ============================================================

interface CartItemViewProps {
  item: import('./types').CartItem;
  onUpdateQuantity: (itemId: number, quantity: number) => void;
  onRemove: (itemId: number) => void;
}

function CartItemView({ item, onUpdateQuantity, onRemove }: CartItemViewProps) {
  return (
    <div className="cart-item">
      <img src={item.product.imageUrl} alt={item.product.name} className="cart-item-image" />
      <div className="cart-item-info">
        <h4>{item.product.name}</h4>
        <p className="cart-item-price">¥{item.product.price.toFixed(2)}</p>
      </div>
      <div className="cart-item-quantity">
        <button
          onClick={() => onUpdateQuantity(item.id, item.quantity - 1)}
          disabled={item.quantity <= 1}
        >
          -
        </button>
        <span>{item.quantity}</span>
        <button
          onClick={() => onUpdateQuantity(item.id, item.quantity + 1)}
          disabled={item.quantity >= item.product.stock}
        >
          +
        </button>
      </div>
      <div className="cart-item-subtotal">
        ¥{(item.product.price * item.quantity).toFixed(2)}
      </div>
      <button className="remove-btn" onClick={() => onRemove(item.id)}>
        删除
      </button>
    </div>
  );
}

interface CartViewProps {
  cart: Cart | null;
  onUpdateQuantity: (itemId: number, quantity: number) => void;
  onRemove: (itemId: number) => void;
  onClearCart: () => void;
}

function CartView({ cart, onUpdateQuantity, onRemove, onClearCart }: CartViewProps) {
  if (!cart || cart.items.length === 0) {
    return (
      <div className="cart-view empty-cart">
        <h2>购物车</h2>
        <p>购物车是空的</p>
      </div>
    );
  }

  const totalAmount = cart.items.reduce(
    (sum, item) => sum + item.product.price * item.quantity,
    0
  );

  return (
    <div className="cart-view">
      <h2>购物车</h2>
      <div className="cart-items">
        {cart.items.map((item) => (
          <CartItemView
            key={item.id}
            item={item}
            onUpdateQuantity={onUpdateQuantity}
            onRemove={onRemove}
          />
        ))}
      </div>
      <div className="cart-summary">
        <div className="cart-total">
          总计: <span>¥{totalAmount.toFixed(2)}</span>
        </div>
        <div className="cart-actions">
          <button onClick={onClearCart} className="clear-cart-btn">
            清空购物车
          </button>
          <button className="checkout-btn">结算</button>
        </div>
      </div>
    </div>
  );
}

// ============================================================
// 主应用组件
// ============================================================

type View = 'products' | 'cart';

function App() {
  // 状态管理
  const [user, setUser] = useState<User | null>(null);
  const [token, setToken] = useState<string | null>(localStorage.getItem('token'));
  const [products, setProducts] = useState<Product[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [cart, setCart] = useState<Cart | null>(null);
  const [currentView, setCurrentView] = useState<View>('products');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<number | null>(null);
  const [searchKeyword, setSearchKeyword] = useState('');

  // 初始化加载
  useEffect(() => {
    loadCategories();
    loadProducts();
  }, []);

  // 加载用户信息和购物车（当 token 变化时）
  useEffect(() => {
    if (token) {
      loadUser();
      loadCart();
    } else {
      setUser(null);
      setCart(null);
    }
  }, [token]);

  // API 请求函数
  const loadUser = async () => {
    try {
      const response = await apiRequest<{ user: User }>('/auth/me');
      setUser(response.user);
    } catch (err) {
      console.error('Failed to load user:', err);
      logout();
    }
  };

  const loadCategories = async () => {
    try {
      const response = await apiRequest<{ categories: Category[] }>('/categories');
      setCategories(response.categories);
    } catch (err) {
      console.error('Failed to load categories:', err);
    }
  };

  const loadProducts = async () => {
    setLoading(true);
    try {
      const params = new URLSearchParams();
      if (selectedCategory) params.append('categoryId', selectedCategory.toString());
      if (searchKeyword) params.append('keyword', searchKeyword);

      const endpoint = `/products${params.toString() ? `?${params.toString()}` : ''}`;
      const response = await apiRequest<{ products: Product[] }>(endpoint);
      setProducts(response.products);
    } catch (err) {
      setError('加载商品失败');
    } finally {
      setLoading(false);
    }
  };

  const loadCart = async () => {
    if (!token) return;
    try {
      const response = await apiRequest<{ cart: Cart }>('/cart');
      setCart(response.cart);
    } catch (err) {
      console.error('Failed to load cart:', err);
    }
  };

  const logout = () => {
    localStorage.removeItem('token');
    setToken(null);
    setUser(null);
    setCart(null);
  };

  const handleAuthSuccess = (newUser: User, newToken: string) => {
    setUser(newUser);
    setToken(newToken);
    loadCart();
  };

  const handleAddToCart = async (productId: number, quantity: number) => {
    if (!token) {
      alert('请先登录');
      return;
    }

    try {
      await apiRequest<{ cart: Cart }>('/cart/items', {
        method: 'POST',
        body: JSON.stringify({ productId, quantity }),
      });
      loadCart();
      alert('已添加到购物车');
    } catch (err) {
      alert(err instanceof Error ? err.message : '添加失败');
    }
  };

  const handleUpdateCartItem = async (itemId: number, quantity: number) => {
    try {
      await apiRequest<{ cart: Cart }>(`/cart/items/${itemId}`, {
        method: 'PATCH',
        body: JSON.stringify({ quantity }),
      });
      loadCart();
    } catch (err) {
      alert(err instanceof Error ? err.message : '更新失败');
    }
  };

  const handleRemoveCartItem = async (itemId: number) => {
    try {
      await apiRequest<{ cart: Cart }>(`/cart/items/${itemId}`, {
        method: 'DELETE',
      });
      loadCart();
    } catch (err) {
      alert(err instanceof Error ? err.message : '删除失败');
    }
  };

  const handleClearCart = async () => {
    if (!confirm('确定要清空购物车吗？')) return;

    try {
      await apiRequest<{ cart: Cart }>('/cart', {
        method: 'DELETE',
      });
      loadCart();
    } catch (err) {
      alert(err instanceof Error ? err.message : '清空失败');
    }
  };

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    loadProducts();
  };

  const cartItemCount = cart?.items.reduce((sum, item) => sum + item.quantity, 0) || 0;

  return (
    <div className="app">
      <header className="header">
        <h1 className="logo">电商平台</h1>
        <nav className="nav">
          <button
            className={currentView === 'products' ? 'active' : ''}
            onClick={() => setCurrentView('products')}
          >
            商品列表
          </button>
          <button
            className={currentView === 'cart' ? 'active' : ''}
            onClick={() => setCurrentView('cart')}
          >
            购物车 {cartItemCount > 0 && <span className="badge">{cartItemCount}</span>}
          </button>
        </nav>
        <AuthView
          user={user}
          onLogout={logout}
          onAuthSuccess={handleAuthSuccess}
        />
      </header>

      <main className="main">
        {error && (
          <div className="error-banner">
            {error}
            <button onClick={() => setError('')}>关闭</button>
          </div>
        )}

        {currentView === 'products' && (
          <div className="products-view">
            <div className="filters">
              <form onSubmit={handleSearch} className="search-form">
                <input
                  type="text"
                  placeholder="搜索商品..."
                  value={searchKeyword}
                  onChange={(e) => setSearchKeyword(e.target.value)}
                />
                <button type="submit">搜索</button>
              </form>
              <div className="category-filter">
                <select
                  value={selectedCategory || ''}
                  onChange={(e) => {
                    setSelectedCategory(e.target.value ? parseInt(e.target.value) : null);
                    loadProducts();
                  }}
                >
                  <option value="">全部分类</option>
                  {categories.map((category) => (
                    <option key={category.id} value={category.id}>
                      {category.name}
                    </option>
                  ))}
                </select>
              </div>
            </div>

            {loading ? (
              <div className="loading">加载中...</div>
            ) : (
              <ProductList
                products={products}
                onAddToCart={handleAddToCart}
                isAuthenticated={!!user}
              />
            )}
          </div>
        )}

        {currentView === 'cart' && (
          <CartView
            cart={cart}
            onUpdateQuantity={handleUpdateCartItem}
            onRemove={handleRemoveCartItem}
            onClearCart={handleClearCart}
          />
        )}
      </main>

      <footer className="footer">
        <p>&copy; 2024 电商平台. All rights reserved.</p>
      </footer>
    </div>
  );
}

export default App;

