interface ProductsProps {
  onNavigateToHome: () => void;
  onNavigateToCart: () => void;
  onAddToCart: (product: Product) => void;
}

const Products: React.FC<ProductsProps> = ({
  onNavigateToHome,
  onNavigateToCart,
  onAddToCart,
}) => {
  const [products, setProducts] = useState<Product[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // 筛选和排序状态
  const [selectedCategory, setSelectedCategory] = useState<number | null>(null);
  const [searchKeyword, setSearchKeyword] = useState('');
  const [sortBy, setSortBy] = useState<ProductSortBy>('createdAt');
  const [sortOrder, setSortOrder] = useState<SortOrder>('desc');
  const [currentPage, setCurrentPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [total, setTotal] = useState(0);

  // 加载商品数据
  const loadProducts = useCallback(async () => {
    try {
      setIsLoading(true);
      const params: ProductQueryParams = {
        page: currentPage,
        limit: 8,
        categoryId: selectedCategory || undefined,
        keyword: searchKeyword || undefined,
        sortBy,
        sortOrder,
      };

      const result = await fetchProducts(params);
      setProducts(result.products);
      setTotalPages(result.totalPages);
      setTotal(result.total);
    } catch (err) {
      setError('加载商品失败，请稍后重试');
      console.error('Error loading products:', err);
    } finally {
      setIsLoading(false);
    }
  }, [currentPage, selectedCategory, searchKeyword, sortBy, sortOrder]);

  // 加载分类数据
  useEffect(() => {
    const loadCategories = async () => {
      try {
        const cats = await fetchCategories();
        setCategories(cats);
      } catch (err) {
        console.error('Error loading categories:', err);
      }
    };
    loadCategories();
  }, []);

  // 当筛选条件变化时重新加载
  useEffect(() => {
    loadProducts();
  }, [loadProducts]);

  // 处理分类选择
  const handleCategoryClick = (categoryId: number | null) => {
    setSelectedCategory(categoryId);
    setCurrentPage(1);
  };

  // 处理搜索
  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    setCurrentPage(1);
    loadProducts();
  };

  // 处理排序变化
  const handleSortChange = (newSortBy: ProductSortBy) => {
    if (newSortBy === sortBy) {
      setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc');
    } else {
      setSortBy(newSortBy);
      setSortOrder('desc');
    }
    setCurrentPage(1);
  };

  // 处理分页
  const handlePageChange = (page: number) => {
    if (page >= 1 && page <= totalPages) {
      setCurrentPage(page);
    }
  };

  // 格式化价格
  const formatPrice = (price: number): string => {
    return `¥${price.toFixed(2)}`;
  };

  // 清除所有筛选
  const clearFilters = () => {
    setSelectedCategory(null);
    setSearchKeyword('');
    setSortBy('createdAt');
    setSortOrder('desc');
    setCurrentPage(1);
  };

  return (
    <div className="products-page">
      {/* Header */}
      <header className="products-header">
        <div className="header-content">
          <button className="logo" onClick={onNavigateToHome}>
            🛒 电商商城
          </button>
          <nav className="header-nav">
            <button className="nav-link" onClick={onNavigateToHome}>
              首页
            </button>
            <button className="nav-link active">商品列表</button>
            <button className="nav-link cart-button" onClick={onNavigateToCart}>
              🛒 购物车
            </button>
          </nav>
        </div>
      </header>

      <div className="products-container">
        {/* 侧边栏 - 分类筛选 */}
        <aside className="sidebar">
          <div className="sidebar-section">
            <h3 className="sidebar-title">商品分类</h3>
            <ul className="category-list">
              <li>
                <button
                  className={`category-item ${selectedCategory === null ? 'active' : ''}`}
                  onClick={() => handleCategoryClick(null)}
                >
                  全部商品
                </button>
              </li>
              {categories.map((category) => (
                <li key={category.id}>
                  <button
                    className={`category-item ${selectedCategory === category.id ? 'active' : ''}`}
                    onClick={() => handleCategoryClick(category.id)}
                  >
                    {category.name}
                  </button>
                </li>
              ))}
            </ul>
          </div>

          <div className="sidebar-section">
            <h3 className="sidebar-title">排序方式</h3>
            <ul className="sort-list">
              <li>
                <button
                  className={`sort-item ${sortBy === 'createdAt' ? 'active' : ''}`}
                  onClick={() => handleSortChange('createdAt')}
                >
                  最新上架
                  {sortBy === 'createdAt' && (
                    <span className="sort-arrow">{sortOrder === 'asc' ? '↑' : '↓'}</span>
                  )}
                </button>
              </li>
              <li>
                <button
                  className={`sort-item ${sortBy === 'price' ? 'active' : ''}`}
                  onClick={() => handleSortChange('price')}
                >
                  价格
                  {sortBy === 'price' && (
                    <span className="sort-arrow">{sortOrder === 'asc' ? '↑' : '↓'}</span>
                  )}
                </button>
              </li>
              <li>
                <button
                  className={`sort-item ${sortBy === 'name' ? 'active' : ''}`}
                  onClick={() => handleSortChange('name')}
                >
                  商品名称
                  {sortBy === 'name' && (
                    <span className="sort-arrow">{sortOrder === 'asc' ? '↑' : '↓'}</span>
                  )}
                </button>
              </li>
            </ul>
          </div>
        </aside>

        {/* 主内容区 */}
        <main className="products-main">
          {/* 搜索栏 */}
          <div className="search-section">
            <form className="search-form" onSubmit={handleSearch}>
              <input
                type="text"
                className="search-input"
                placeholder="搜索商品..."
                value={searchKeyword}
                onChange={(e) => setSearchKeyword(e.target.value)}
              />
              <button type="submit" className="search-button">
                🔍 搜索
              </button>
            </form>
            {(selectedCategory !== null || searchKeyword) && (
              <button className="clear-filters-button" onClick={clearFilters}>
                ✕ 清除筛选
              </button>
            )}
          </div>

          {/* 结果统计 */}
          <div className="results-info">
            <p>
              共找到 <strong>{total}</strong> 件商品
              {selectedCategory !== null && (
                <span>
                  {' '}
                  - 分类: {categories.find((c) => c.id === selectedCategory)?.name}
                </span>
              )}
              {searchKeyword && <span> - 关键词: "{searchKeyword}"</span>}
            </p>
          </div>

          {/* 加载状态 */}
          {isLoading ? (
            <div className="loading-container">
              <div className="loading-spinner" />
              <p>加载中...</p>
            </div>
          ) : error ? (
            <div className="error-container">
              <p className="error-message">{error}</p>
              <button onClick={loadProducts} className="retry-button">
                重试
              </button>
            </div>
          ) : products.length === 0 ? (
            <div className="empty-container">
              <p>没有找到相关商品</p>
              <button onClick={clearFilters} className="clear-filters-button">
                清除筛选条件
              </button>
            </div>
          ) : (
            <>
              {/* 商品列表 */}
              <div className="products-grid">
                {products.map((product) => (
                  <div key={product.id} className="product-card">
                    <div className="product-image-container">
                      <img
                        src={product.imageUrl}
                        alt={product.name}
                        className="product-image"
                      />
                      {product.stock === 0 && (
                        <div className="sold-out-overlay">
                          <span>已售罄</span>
                        </div>
                      )}
                      {product.stock > 0 && product.stock < 20 && (
                        <span className="stock-badge">库存紧张</span>
                      )}
                    </div>
                    <div className="product-info">
                      <h3 className="product-name">{product.name}</h3>
                      <p className="product-description">{product.description}</p>
                      <div className="product-meta">
                        <span className="product-price">
                          {formatPrice(product.price)}
                        </span>
                        <span className="product-stock">
                          库存: {product.stock}
                        </span>
                      </div>
                      <button
                        className="add-to-cart-button"
                        onClick={() => onAddToCart(product)}
                        disabled={product.stock === 0}
                      >
                        {product.stock === 0 ? '已售罄' : '加入购物车'}
                      </button>
                    </div>
                  </div>
                ))}
              </div>

              {/* 分页组件 */}
              {totalPages > 1 && (
                <div className="pagination">
                  <button
                    className="pagination-button"
                    onClick={() => handlePageChange(currentPage - 1)}
                    disabled={currentPage === 1}
                  >
                    上一页
                  </button>

                  <div className="pagination-numbers">
                    {Array.from({ length: totalPages }, (_, i) => i + 1)
                      .filter((page) => {
                        return (
                          page === 1 ||
                          page === totalPages ||
                          Math.abs(page - currentPage) <= 2
                        );
                      })
                      .map((page, index, array) => {
                        const showEllipsis =
                          index > 0 && page - array[index - 1] > 1;

                        return (
                          <React.Fragment key={page}>
                            {showEllipsis && (
                              <span className="pagination-ellipsis">...</span>
                            )}
                            <button
                              className={`pagination-number ${currentPage === page ? 'active' : ''}`}
                              onClick={() => handlePageChange(page)}
                            >
                              {page}
                            </button>
                          </React.Fragment>
                        );
                      })}
                  </div>

                  <button
                    className="pagination-button"
                    onClick={() => handlePageChange(currentPage + 1)}
                    disabled={currentPage === totalPages}
                  >
                    下一页
                  </button>
                </div>
              )}
            </>
          )}
        </main>
      </div>

      {/* Footer */}
      <footer className="products-footer">
        <p>© 2024 电商商城. All rights reserved.</p>
      </footer>
    </div>
  );
};

