interface CartProps {
  onNavigateToHome: () => void;
  onNavigateToProducts: () => void;
  initialCartItems?: CartItem[];
  onCheckout?: (items: CartItem[]) => void;
}

const Cart: React.FC<CartProps> = ({
  onNavigateToHome,
  onNavigateToProducts,
  initialCartItems,
  onCheckout,
}) => {
  const [cartItems, setCartItems] = useState<CartItem[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [selectedItems, setSelectedItems] = useState<Set<number>>(new Set());
  const [isCheckingOut, setIsCheckingOut] = useState(false);

  // 加载购物车数据
  useEffect(() => {
    const loadCart = async () => {
      try {
        setIsLoading(true);
        // 模拟API调用延迟
        await new Promise((resolve) => setTimeout(resolve, 500));

        // 使用初始数据或模拟数据
        const items = initialCartItems || mockCart.items;
        setCartItems(items);

        // 默认选中所有商品
        setSelectedItems(new Set(items.map((item) => item.id)));
      } catch (err) {
        setError('加载购物车失败，请稍后重试');
        console.error('Error loading cart:', err);
      } finally {
        setIsLoading(false);
      }
    };

    loadCart();
  }, [initialCartItems]);

  // 计算选中商品的总价
  const calculateTotal = useCallback((): number => {
    return cartItems
      .filter((item) => selectedItems.has(item.id))
      .reduce((sum, item) => sum + item.product.price * item.quantity, 0);
  }, [cartItems, selectedItems]);

  // 计算选中商品的总数量
  const calculateTotalQuantity = useCallback((): number => {
    return cartItems
      .filter((item) => selectedItems.has(item.id))
      .reduce((sum, item) => sum + item.quantity, 0);
  }, [cartItems, selectedItems]);

  // 更新商品数量
  const updateQuantity = (itemId: number, newQuantity: number) => {
    if (newQuantity < 1) return;

    setCartItems((prevItems) =>
      prevItems.map((item) =>
        item.id === itemId ? { ...item, quantity: newQuantity } : item
      )
    );
  };

  // 移除商品
  const removeItem = (itemId: number) => {
    setCartItems((prevItems) => prevItems.filter((item) => item.id !== itemId));
    setSelectedItems((prevSelected) => {
      const newSelected = new Set(prevSelected);
      newSelected.delete(itemId);
      return newSelected;
    });
  };

  // 切换商品选中状态
  const toggleItemSelection = (itemId: number) => {
    setSelectedItems((prevSelected) => {
      const newSelected = new Set(prevSelected);
      if (newSelected.has(itemId)) {
        newSelected.delete(itemId);
      } else {
        newSelected.add(itemId);
      }
      return newSelected;
    });
  };

  // 全选/取消全选
  const toggleSelectAll = () => {
    if (selectedItems.size === cartItems.length) {
      setSelectedItems(new Set());
    } else {
      setSelectedItems(new Set(cartItems.map((item) => item.id)));
    }
  };

  // 清空购物车
  const clearCart = () => {
    if (window.confirm('确定要清空购物车吗？')) {
      setCartItems([]);
      setSelectedItems(new Set());
    }
  };

  // 清空已选商品
  const removeSelectedItems = () => {
    if (selectedItems.size === 0) return;

    if (window.confirm(`确定要移除选中的 ${selectedItems.size} 件商品吗？`)) {
      setCartItems((prevItems) =>
        prevItems.filter((item) => !selectedItems.has(item.id))
      );
      setSelectedItems(new Set());
    }
  };

  // 结算
  const handleCheckout = async () => {
    if (selectedItems.size === 0) return;

    const selectedCartItems = cartItems.filter((item) => selectedItems.has(item.id));

    // 检查库存
    const outOfStockItems = selectedCartItems.filter(
      (item) => item.quantity > item.product.stock
    );

    if (outOfStockItems.length > 0) {
      alert(
        `以下商品库存不足：\n${outOfStockItems.map((item) => item.product.name).join('\n')}`
      );
      return;
    }

    setIsCheckingOut(true);

    try {
      // 模拟结算API调用
      await new Promise((resolve) => setTimeout(resolve, 1000));

      // 调用结算回调
      if (onCheckout) {
        onCheckout(selectedCartItems);
      }

      alert('结算成功！感谢您的购买！');

      // 从购物车移除已结算的商品
      setCartItems((prevItems) =>
        prevItems.filter((item) => !selectedItems.has(item.id))
      );
      setSelectedItems(new Set());
    } catch (err) {
      alert('结算失败，请稍后重试');
      console.error('Checkout error:', err);
    } finally {
      setIsCheckingOut(false);
    }
  };

  // 格式化价格
  const formatPrice = (price: number): string => {
    return `¥${price.toFixed(2)}`;
  };

  const total = calculateTotal();
  const totalQuantity = calculateTotalQuantity();
  const isAllSelected = cartItems.length > 0 && selectedItems.size === cartItems.length;

  return (
    <div className="cart-page">
      {/* Header */}
      <header className="cart-header">
        <div className="header-content">
          <button className="logo" onClick={onNavigateToHome}>
            🛒 电商商城
          </button>
          <nav className="header-nav">
            <button className="nav-link" onClick={onNavigateToHome}>
              首页
            </button>
            <button className="nav-link" onClick={onNavigateToProducts}>
              商品列表
            </button>
            <button className="nav-link active">🛒 购物车</button>
          </nav>
        </div>
      </header>

      <div className="cart-container">
        {isLoading ? (
          <div className="loading-container">
            <div className="loading-spinner" />
            <p>加载购物车...</p>
          </div>
        ) : error ? (
          <div className="error-container">
            <p className="error-message">{error}</p>
            <button onClick={() => window.location.reload()} className="retry-button">
              重试
            </button>
          </div>
        ) : cartItems.length === 0 ? (
          <div className="empty-cart">
            <div className="empty-cart-icon">🛒</div>
            <h2>购物车是空的</h2>
            <p>快去挑选心仪的商品吧！</p>
            <button className="shopping-button" onClick={onNavigateToProducts}>
              去购物
            </button>
          </div>
        ) : (
          <>
            {/* 购物车工具栏 */}
            <div className="cart-toolbar">
              <div className="toolbar-left">
                <label className="select-all-label">
                  <input
                    type="checkbox"
                    checked={isAllSelected}
                    onChange={toggleSelectAll}
                    className="select-checkbox"
                  />
                  <span>全选</span>
                </label>
                <button
                  className="toolbar-button"
                  onClick={removeSelectedItems}
                  disabled={selectedItems.size === 0}
                >
                  移除选中 ({selectedItems.size})
                </button>
              </div>
              <button className="toolbar-button danger" onClick={clearCart}>
                清空购物车
              </button>
            </div>

            {/* 购物车商品列表 */}
            <div className="cart-items">
              {cartItems.map((item) => (
                <div
                  key={item.id}
                  className={`cart-item ${selectedItems.has(item.id) ? 'selected' : ''}`}
                >
                  <div className="item-checkbox">
                    <input
                      type="checkbox"
                      checked={selectedItems.has(item.id)}
                      onChange={() => toggleItemSelection(item.id)}
                      className="select-checkbox"
                    />
                  </div>

                  <div className="item-image">
                    <img
                      src={item.product.imageUrl}
                      alt={item.product.name}
                    />
                  </div>

                  <div className="item-details">
                    <h3 className="item-name">{item.product.name}</h3>
                    <p className="item-description">{item.product.description}</p>
                    <div className="item-stock-info">
                      {item.quantity > item.product.stock ? (
                        <span className="stock-warning">
                          ⚠️ 库存不足（仅剩 {item.product.stock} 件）
                        </span>
                      ) : (
                        <span className="stock-ok">
                          库存: {item.product.stock}
                        </span>
                      )}
                    </div>
                  </div>

                  <div className="item-price">
                    {formatPrice(item.product.price)}
                  </div>

                  <div className="item-quantity">
                    <button
                      className="quantity-button"
                      onClick={() => updateQuantity(item.id, item.quantity - 1)}
                      disabled={item.quantity <= 1}
                    >
                      -
                    </button>
                    <input
                      type="number"
                      className="quantity-input"
                      value={item.quantity}
                      onChange={(e) => {
                        const value = parseInt(e.target.value);
                        if (!isNaN(value) && value > 0) {
                          updateQuantity(item.id, value);
                        }
                      }}
                      min="1"
                      max={item.product.stock}
                    />
                    <button
                      className="quantity-button"
                      onClick={() => updateQuantity(item.id, item.quantity + 1)}
                      disabled={item.quantity >= item.product.stock}
                    >
                      +
                    </button>
                  </div>

                  <div className="item-subtotal">
                    {formatPrice(item.product.price * item.quantity)}
                  </div>

                  <button
                    className="remove-button"
                    onClick={() => removeItem(item.id)}
                    title="移除商品"
                  >
                    ✕
                  </button>
                </div>
              ))}
            </div>

            {/* 购物车结算栏 */}
            <div className="cart-summary">
              <div className="summary-info">
                <div className="summary-row">
                  <span>已选商品 ({totalQuantity}) 件</span>
                </div>
                <div className="summary-row">
                  <span>商品总价:</span>
                  <span className="summary-value">{formatPrice(total)}</span>
                </div>
                <div className="summary-row">
                  <span>运费:</span>
                  <span className="summary-value">
                    {total >= 99 ? '免费' : '¥10.00'}
                  </span>
                </div>
                {total < 99 && (
                  <div className="shipping-tip">
                    <span>📦 订单满99元免运费，再买 {formatPrice(99 - total)}</span>
                  </div>
                )}
                <div className="summary-row total">
                  <span>应付总额:</span>
                  <span className="summary-total">
                    {formatPrice(total >= 99 ? total : total + 10)}
                  </span>
                </div>
              </div>

              <div className="summary-actions">
                <button
                  className="continue-shopping-button"
                  onClick={onNavigateToProducts}
                >
                  继续购物
                </button>
                <button
                  className="checkout-button"
                  onClick={handleCheckout}
                  disabled={selectedItems.size === 0 || isCheckingOut}
                >
                  {isCheckingOut ? '结算中...' : '去结算'}
                </button>
              </div>
            </div>
          </>
        )}
      </div>

      {/* 推荐商品区域 */}
      {!isLoading && cartItems.length > 0 && (
        <section className="recommended-section">
          <h2 className="section-title">猜你喜欢</h2>
          <div className="recommended-grid">
            <div className="recommended-item">
              <img
                src="https://via.placeholder.com/150x150?text=Apple+Watch"
                alt="Apple Watch"
              />
              <h4>Apple Watch</h4>
              <p className="recommended-price">¥2999.00</p>
            </div>
            <div className="recommended-item">
              <img
                src="https://via.placeholder.com/150x150?text=iPod+Touch"
                alt="iPod Touch"
              />
              <h4>iPod Touch</h4>
              <p className="recommended-price">¥1599.00</p>
            </div>
            <div className="recommended-item">
              <img
                src="https://via.placeholder.com/150x150?text=Magic+Mouse"
                alt="Magic Mouse"
              />
              <h4>Magic Mouse</h4>
              <p className="recommended-price">¥699.00</p>
            </div>
            <div className="recommended-item">
              <img
                src="https://via.placeholder.com/150x150?text=AirTag"
                alt="AirTag"
              />
              <h4>AirTag</h4>
              <p className="recommended-price">¥229.00</p>
            </div>
          </div>
        </section>
      )}

      {/* Footer */}
      <footer className="cart-footer">
        <p>© 2024 电商商城. All rights reserved.</p>
      </footer>
    </div>
  );
};

export default Cart;

